mapper.select:
SELECT r.id, r.register_no as register_no, r.pet_id, r.owner_user_id as owner_id, r.doctor_id, r.service_item_id as service_type, r.triage_note as symptom, r.status, r.amount, r.register_time as visit_time, r.accept_time, r.create_time, p.name as pet_name, p.type as pet_type, p.breed, p.age, p.gender, u.real_name as owner_name, u.phone as owner_phone FROM register_record r LEFT JOIN pet p ON r.pet_id = p.id LEFT JOIN sys_user u ON r.owner_user_id = u.id WHERE 1=1
AND r.status = #{status}
AND ( p.name LIKE CONCAT('%', #{keyword}, '%') OR u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.phone LIKE CONCAT('%', #{keyword}, '%') OR r.register_no LIKE CONCAT('%', #{keyword}, '%') )
AND r.doctor_id = #{doctorId}
ORDER BY r.register_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM register_record r LEFT JOIN pet p ON r.pet_id = p.id LEFT JOIN sys_user u ON r.owner_user_id = u.id WHERE 1=1
AND r.status = #{status}
AND ( p.name LIKE CONCAT('%', #{keyword}, '%') OR u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.phone LIKE CONCAT('%', #{keyword}, '%') OR r.register_no LIKE CONCAT('%', #{keyword}, '%') )
AND r.doctor_id = #{doctorId}
